//-------------------------------------------------------------------------
// 엑셀 다운로드
//-------------------------------------------------------------------------
scwin.f_downExcelSheet = async function () {
    let totCnt = ds_item.getRowCount();
    let sheetTitle = "매출입항목관리";

    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            const options = {
                fileName: sheetTitle + ".xlsx",
                sheetName: sheetTitle
            };
            $c.data.downloadGridViewExcel(gr_item, options);
        }
    } else {
        await $c.win.alert(MSG_CM_WRN_002);
    }
};
